shared_basics.template:
#include <iostream>
#include <cstdio>
#include <memory>
int main() {
    std::weak_ptr<int> wp;
    {
        auto sp1 = std::make_shared<int>(<<value>>);
        wp = sp1;
        std::cout << "use_count: " << sp1.use_count() << "  (1 owner)" << std::endl;
        {
            auto sp2 = sp1;  // copy: use_count -> 2
            std::cout << "use_count: " << sp1.use_count() << "  (2 owners)" << std::endl;
            printf("PTRDATA: type=shared ptr_addr=%p ptr2_addr=%p target_addr=%p val=%d use_count=%ld\n",
                   (void*)&sp1, (void*)&sp2, (void*)sp1.get(), *sp1, (long)sp1.use_count());
        }  // sp2 destroyed: use_count -> 1
        std::cout << "use_count: " << sp1.use_count() << "  (1 owner, sp2 gone)" << std::endl;
        <<HARNESS>>
    }  // sp1 destroyed: use_count -> 0, heap object freed
    std::cout << "use_count: " << wp.use_count() << "  (0 owners, object freed)" << std::endl;
    std::cout << "expired:   " << (wp.expired() ? "true" : "false") << std::endl;
}

shared_copy.template:
#include <iostream>
#include <cstdio>
#include <memory>
int main() {
    auto sp1 = std::make_shared<int>(42);
    {
        auto sp2 = sp1;  // copy: use_count becomes 2
        std::cout << "use_count after copy: " << sp1.use_count() << std::endl;
        printf("PTRDATA: type=shared ptr_addr=%p ptr2_addr=%p target_addr=%p val=%d use_count=%ld\n",
               (void*)&sp1, (void*)&sp2, (void*)sp1.get(), *sp1, (long)sp1.use_count());
    }
    std::cout << "use_count after sp2 scope: " << sp1.use_count() << std::endl;
    <<HARNESS>>
}

weak_basics.template:
#include <iostream>
#include <cstdio>
#include <memory>
int main() {
    auto sp = std::make_shared<int>(<<value>>);
    std::weak_ptr<int> wp = sp;
    std::cout << "use_count with weak_ptr: " << sp.use_count() << std::endl;
    printf("PTRDATA: type=weak ptr_addr=%p expired=%d use_count=%ld\n",
           (void*)&wp, (int)wp.expired(), (long)sp.use_count());
    if (auto locked = wp.lock()) {
        std::cout << "locked val=" << *locked << std::endl;
    }
    <<HARNESS>>
}

weak_expired.template:
#include <iostream>
#include <cstdio>
#include <memory>
int main() {
    std::weak_ptr<int> wp;
    {
        auto sp = std::make_shared<int>(55);
        wp = sp;
        std::cout << "use_count inside scope: " << sp.use_count() << std::endl;
    }  // sp destroyed here — wp becomes expired
    printf("PTRDATA: type=weak ptr_addr=%p expired=%d use_count=%ld\n",
           (void*)&wp, (int)wp.expired(), (long)wp.use_count());
    std::cout << "expired: " << (wp.expired() ? "true" : "false") << std::endl;
    std::cout << "lock empty: " << (!wp.lock() ? "true" : "false") << std::endl;
    <<HARNESS>>
}

weak_cycle.template:
#include <iostream>
#include <memory>

struct B;

struct A {
    std::shared_ptr<B> b_ptr;
    ~A() { std::cout << "A destroyed" << std::endl; }
};
struct B {
    <<b_ptr_decl>>
    ~B() { std::cout << "B destroyed" << std::endl; }
};

int main() {
    auto a = std::make_shared<A>();
    auto b = std::make_shared<B>();
    a->b_ptr = b;
    b->a_ptr = a;
    std::cout << "a.use_count: " << a.use_count() << std::endl;
    std::cout << "b.use_count: " << b.use_count() << std::endl;
    // a and b go out of scope here
}
